1	type Cell = [number, number]; // [x, y]
2	
3	const NEIGHBOR_COUNT_FOR_REPRODUCTION = 3;
4	const NEIGHBOR_COUNT_FOR_SURVIVAL = 2;
5	
6	const NEIGHBOR_OFFSETS: Cell[] = [
7	  [-1, -1], [0, -1], [1, -1],
8	  [-1, 0], [1, 0],
9	  [-1, 1], [0, 1], [1, 1],
10	];
11	
12	function toKey([x, y]: Cell): string {
13	  return `${x},${y}`;
14	}
15	
16	function fromKey(key: string): Cell {
17	  const [x, y] = key.split(",").map(Number);
18	  return [x, y];
19	}
20	
21	function neighborsOf([x, y]: Cell): Cell[] {
22	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
23	}
24	
25	function candidateCells(cells: Cell[]): Set<string> {
26	  const candidates = new Set<string>();
27	  for (const cell of cells) {
28	    candidates.add(toKey(cell));
29	    for (const neighbor of neighborsOf(cell)) {
30	      candidates.add(toKey(neighbor));
31	    }
32	  }
33	  return candidates;
34	}
35	
36	function countLiveNeighbors(cell: Cell, living: Set<string>): number {
37	  return neighborsOf(cell).filter((neighbor) => living.has(toKey(neighbor)))
38	    .length;
39	}
40	
41	function survivesOrIsBorn(cell: Cell, living: Set<string>): boolean {
42	  const liveNeighbors = countLiveNeighbors(cell, living);
43	  const isAlive = living.has(toKey(cell));
44	  return (
45	    liveNeighbors === NEIGHBOR_COUNT_FOR_REPRODUCTION ||
46	    (isAlive && liveNeighbors === NEIGHBOR_COUNT_FOR_SURVIVAL)
47	  );
48	}
49	
50	export function nextGeneration(cells: Cell[]): Cell[] {
51	  const living = new Set(cells.map(toKey));
52	  return [...candidateCells(cells)]
53	    .map(fromKey)
54	    .filter((cell) => survivesOrIsBorn(cell, living));
55	}
